import java.util.ArrayList;
import java.util.List;
import java.util.Random;

class Solution {
    private int match(String a, String b) {
        int matches = 0;
        for (int i = 0; i < 6; ++i)
            if (a.charAt(i) == b.charAt(i)) matches++;
        return matches;
    }

    public void findSecretWord(String[] wordlist, Master master) {
        List<String> words = new ArrayList<>();
        for (String word : wordlist) words.add(word);
        Random rand = new Random();

        for (int i = 0, matchCnt = 0; i < 10 && matchCnt < 6; ++i) {
            String guess = words.get(rand.nextInt(words.size()));
            matchCnt = master.guess(guess);
            List<String> candidates = new ArrayList<>();
            for (String word : words)
                if (match(word, guess) == matchCnt)
                    candidates.add(word);
            words = candidates;
        }
    }
}
```

    1. Define a `match` function to calculate the number of exact matches between two strings.
2. For 10 iterations or until the secret word is guessed:
  a. Randomly select a word (`guess`) from the `wordlist`.
  b. Call `Master.guess` with the `guess`, and store the number of exact matches in `match_cnt`.
  c. If the `match_cnt` equals 6 (i.e., the word is guessed), terminate the loop.
  d. Filter the `wordlist` to keep only those words that have the same number of exact matches with the `guess` as `match_cnt`.
3. Complete the loop and return.
